CREATE OR REPLACE FUNCTION compare_relfilenode_part(tabname text) RETURNS TABLE (relname name, relkind "char", state text) AS $func$ BEGIN RETURN QUERY EXECUTE format( 'SELECT b.relname, b.relkind, CASE WHEN a.relfilenode = b.relfilenode THEN ''relfilenode is unchanged'' ELSE ''relfilenode has changed'' END -- Do not join with OID here as CONCURRENTLY changes it. FROM %I b JOIN pg_class a ON b.relname = a.relname ORDER BY 1;', tabname); END $func$ LANGUAGE plpgsql
