CALL nonexistent()
CALL random()
CREATE FUNCTION cp_testfunc1(a int) RETURNS int LANGUAGE SQL AS $$ SELECT a $$
CREATE TABLE cp_test (a int, b text)
CREATE PROCEDURE ptest1(x text) LANGUAGE SQL AS $$ INSERT INTO cp_test VALUES (1, x); $$
SELECT pg_get_functiondef('ptest1'::regproc)
SELECT ptest1('x')
CALL ptest1('a')
CALL ptest1('xy' || 'zzy')
CALL ptest1(substring(random()::numeric(20,15)::text, 1, 1))
SELECT * FROM cp_test ORDER BY b COLLATE "C"
CREATE PROCEDURE ptest1s(x text) LANGUAGE SQL BEGIN ATOMIC INSERT INTO cp_test VALUES (1, x)
SELECT pg_get_functiondef('ptest1s'::regproc)
CALL ptest1s('b')
CREATE PROCEDURE ptestx() LANGUAGE SQL BEGIN ATOMIC CREATE TABLE x (a int)
CREATE PROCEDURE ptest2() LANGUAGE SQL AS $$ SELECT 5; $$
CALL ptest2()
TRUNCATE cp_test
CREATE PROCEDURE ptest3(y text) LANGUAGE SQL AS $$ CALL ptest1(y); CALL ptest1($1); $$
CALL ptest3('b')
SELECT * FROM cp_test
CREATE PROCEDURE ptest4a(INOUT a int, INOUT b int) LANGUAGE SQL AS $$ SELECT 1, 2; $$
CALL ptest4a(NULL, NULL)
CREATE PROCEDURE ptest4b(INOUT b int, INOUT a int) LANGUAGE SQL AS $$ CALL ptest4a(a, b); -- error, not supported $$
CREATE PROCEDURE ptest4c(INOUT comp int8_tbl) LANGUAGE SQL AS $$ SELECT ROW(1, 2); $$
CALL ptest4c(NULL)
DROP PROCEDURE ptest4a, ptest4c
CREATE OR REPLACE PROCEDURE ptest5(a int, b text, c int default 100) LANGUAGE SQL AS $$ INSERT INTO cp_test VALUES(a, b); INSERT INTO cp_test VALUES(c, b); $$
CALL ptest5(10, 'Hello', 20)
CALL ptest5(10, 'Hello')
