SELECT v as value, hash_multirange(v)::bit(32) as standard, hash_multirange_extended(v, 0)::bit(32) as extended0, hash_multirange_extended(v, 1)::bit(32) as extended1 FROM (VALUES ('{[10,20)}'::int4multirange), ('{[23, 43]}'::int4multirange), ('{[5675, 550273)}'::int4multirange), ('{[550274, 1550274)}'::int4multirange), ('{[1550275, 208112489)}'::int4multirange)) x(v) WHERE hash_multirange(v)::bit(32) != hash_multirange_extended(v, 0)::bit(32) OR hash_multirange(v)::bit(32) = hash_multirange_extended(v, 1)::bit(32)
CREATE TYPE hash_test_t1 AS (a int, b text)
SELECT v as value, hash_record(v)::bit(32) as standard, hash_record_extended(v, 0)::bit(32) as extended0, hash_record_extended(v, 1)::bit(32) as extended1 FROM (VALUES (row(1, 'aaa')::hash_test_t1, row(2, 'bbb'), row(-1, 'ccc'))) x(v) WHERE hash_record(v)::bit(32) != hash_record_extended(v, 0)::bit(32) OR hash_record(v)::bit(32) = hash_record_extended(v, 1)::bit(32)
DROP TYPE hash_test_t1
CREATE TYPE hash_test_t2 AS (a varbit, b text)
SELECT v as value, hash_record(v)::bit(32) as standard FROM (VALUES (row('10'::varbit, 'aaa')::hash_test_t2)) x(v)
SELECT v as value, hash_record_extended(v, 0)::bit(32) as extended0 FROM (VALUES (row('11'::varbit, 'aaa')::hash_test_t2)) x(v)
DROP TYPE hash_test_t2
