# file: src/test/regress/sql/largeobject.sql
SET bytea_output TO escape
CREATE ROLE regress_lo_user
SELECT lo_create(42)
ALTER LARGE OBJECT 42 OWNER TO regress_lo_user
SET SESSION AUTHORIZATION regress_lo_user
GRANT SELECT ON LARGE OBJECT 42 TO public
COMMENT ON LARGE OBJECT 42 IS 'the ultimate answer'
CREATE TABLE lotest_stash_values (loid oid, fd integer)
INSERT INTO lotest_stash_values (loid) SELECT lo_creat(42)
UPDATE lotest_stash_values SET fd = lo_open(loid, CAST(x'20000' | x'40000' AS integer))
SELECT lowrite(fd, ' I wandered lonely as a cloud That floats on high o''er vales and hills, When all at once I saw a crowd, A host, of golden daffodils; Beside the lake, beneath the trees, Fluttering and dancing in the breeze. Continuous as the stars that shine And twinkle on the milky way, They stretched in never-ending line Along the margin of a bay: Ten thousand saw I at a glance, Tossing their heads in sprightly dance. The waves beside them danced; but they Out-did the sparkling waves in glee: A poet could not but be gay, In such a jocund company: I gazed--and gazed--but little thought What wealth the show to me had brought: For oft, when on my couch I lie In vacant or in pensive mood, They flash upon that inward eye Which is the bliss of solitude; And then my heart with pleasure fills, And dances with the daffodils. -- William Wordsworth ') FROM lotest_stash_values
SELECT lo_close(fd) FROM lotest_stash_values
SELECT lo_from_bytea(0, lo_get(loid)) AS newloid FROM lotest_stash_values
COMMENT ON LARGE OBJECT :newloid IS 'I Wandered Lonely as a Cloud'
UPDATE lotest_stash_values SET fd=lo_open(loid, CAST(x'20000' | x'40000' AS integer))
SELECT lo_lseek(fd, 104, 0) FROM lotest_stash_values
SELECT loread(fd, 28) FROM lotest_stash_values
SELECT lo_lseek(fd, -19, 1) FROM lotest_stash_values
SELECT lowrite(fd, 'n') FROM lotest_stash_values
SELECT lo_tell(fd) FROM lotest_stash_values
SELECT lo_lseek(fd, -744, 2) FROM lotest_stash_values
SELECT lo_open(loid, x'40000'::int) from lotest_stash_values
SELECT lo_truncate(fd, 11) FROM lotest_stash_values
SELECT loread(fd, 15) FROM lotest_stash_values
SELECT lo_truncate(fd, 10000) FROM lotest_stash_values
SELECT loread(fd, 10) FROM lotest_stash_values
SELECT lo_lseek(fd, 0, 2) FROM lotest_stash_values
SELECT lo_truncate(fd, 5000) FROM lotest_stash_values
SELECT lo_lseek64(fd, 4294967296, 0) FROM lotest_stash_values
