WITH objects (classid, objid, objsubid) AS (VALUES ('pg_class'::regclass, 0, 0), ('pg_class'::regclass, 'pg_class'::regclass, 100), ('pg_proc'::regclass, 0, 0), ('pg_type'::regclass, 0, 0), ('pg_cast'::regclass, 0, 0), ('pg_collation'::regclass, 0, 0), ('pg_constraint'::regclass, 0, 0), ('pg_conversion'::regclass, 0, 0), ('pg_attrdef'::regclass, 0, 0), ('pg_language'::regclass, 0, 0), ('pg_largeobject'::regclass, 0, 0), ('pg_operator'::regclass, 0, 0), ('pg_opclass'::regclass, 0, 0), ('pg_opfamily'::regclass, 0, 0), ('pg_am'::regclass, 0, 0), ('pg_amop'::regclass, 0, 0), ('pg_amproc'::regclass, 0, 0), ('pg_rewrite'::regclass, 0, 0), ('pg_trigger'::regclass, 0, 0), ('pg_namespace'::regclass, 0, 0), ('pg_statistic_ext'::regclass, 0, 0), ('pg_ts_parser'::regclass, 0, 0), ('pg_ts_dict'::regclass, 0, 0), ('pg_ts_template'::regclass, 0, 0), ('pg_ts_config'::regclass, 0, 0), ('pg_authid'::regclass, 0, 0), ('pg_auth_members'::regclass, 0, 0), ('pg_database'::regclass, 0, 0), ('pg_tablespace'::regclass, 0, 0), ('pg_foreign_data_wrapper'::regclass, 0, 0), ('pg_foreign_server'::regclass, 0, 0), ('pg_user_mapping'::regclass, 0, 0), ('pg_default_acl'::regclass, 0, 0), ('pg_extension'::regclass, 0, 0), ('pg_event_trigger'::regclass, 0, 0), ('pg_parameter_acl'::regclass, 0, 0), ('pg_policy'::regclass, 0, 0), ('pg_publication'::regclass, 0, 0), ('pg_publication_namespace'::regclass, 0, 0), ('pg_publication_rel'::regclass, 0, 0), ('pg_subscription'::regclass, 0, 0), ('pg_transform'::regclass, 0, 0) ) SELECT ROW(pg_identify_object(objects.classid, objects.objid, objects.objsubid)) AS ident, ROW(pg_identify_object_as_address(objects.classid, objects.objid, objects.objsubid)) AS addr, pg_describe_object(objects.classid, objects.objid, objects.objsubid) AS descr FROM objects ORDER BY objects.classid, objects.objid, objects.objsubid
