CREATE FUNCTION ks_test_uniform_random_int_in_range() RETURNS boolean AS $$ DECLARE n int := 1000; -- Number of samples c float8 := 1.94947; -- Critical value for 99.9% confidence ok boolean; BEGIN ok := ( WITH samples AS ( SELECT random(0, 999999) / 1000000.0 r FROM generate_series(1, n) ORDER BY 1 ), indexed_samples AS ( SELECT (row_number() OVER())-1.0 i, r FROM samples ) SELECT max(abs(i/n-r)) < c / sqrt(n) FROM indexed_samples ); RETURN ok; END $$ LANGUAGE plpgsql
SELECT ks_test_uniform_random_int_in_range() OR ks_test_uniform_random_int_in_range() OR ks_test_uniform_random_int_in_range() AS uniform_int
CREATE FUNCTION ks_test_uniform_random_bigint_in_range() RETURNS boolean AS $$ DECLARE n int := 1000; -- Number of samples c float8 := 1.94947; -- Critical value for 99.9% confidence ok boolean; BEGIN ok := ( WITH samples AS ( SELECT random(0, 999999999999) / 1000000000000.0 r FROM generate_series(1, n) ORDER BY 1 ), indexed_samples AS ( SELECT (row_number() OVER())-1.0 i, r FROM samples ) SELECT max(abs(i/n-r)) < c / sqrt(n) FROM indexed_samples ); RETURN ok; END $$ LANGUAGE plpgsql
SELECT ks_test_uniform_random_bigint_in_range() OR ks_test_uniform_random_bigint_in_range() OR ks_test_uniform_random_bigint_in_range() AS uniform_bigint
CREATE FUNCTION ks_test_uniform_random_numeric_in_range() RETURNS boolean AS $$ DECLARE n int := 1000; -- Number of samples c float8 := 1.94947; -- Critical value for 99.9% confidence ok boolean; BEGIN ok := ( WITH samples AS ( SELECT random(0, 0.999999) r FROM generate_series(1, n) ORDER BY 1 ), indexed_samples AS ( SELECT (row_number() OVER())-1.0 i, r FROM samples ) SELECT max(abs(i/n-r)) < c / sqrt(n) FROM indexed_samples ); RETURN ok; END $$ LANGUAGE plpgsql
SELECT ks_test_uniform_random_numeric_in_range() OR ks_test_uniform_random_numeric_in_range() OR ks_test_uniform_random_numeric_in_range() AS uniform_numeric
