update convslot_test_parent set col1 = col1 || '1'
create function convslot_trig3() returns trigger language plpgsql AS $$ begin raise notice 'trigger = %, old_table = %, new table = %', TG_NAME, (select string_agg(old_table::text, ', ' order by col1) from old_table), (select string_agg(new_table::text, ', ' order by col1) from new_table); return null; end; $$
create trigger but_trigger2 after update on convslot_test_child referencing old table as old_table new table as new_table for each statement execute function convslot_trig3()
create trigger bdt_trigger after delete on convslot_test_child referencing old table as old_table for each statement execute function convslot_trig1()
delete from convslot_test_parent
drop table convslot_test_child, convslot_test_parent
drop function convslot_trig1()
drop function convslot_trig2()
drop function convslot_trig3()
create table convslot_test_parent (id int primary key, val int) partition by range (id)
create table convslot_test_part (val int, id int not null)
alter table convslot_test_parent attach partition convslot_test_part for values from (1) to (1000)
create function convslot_trig4() returns trigger as $$begin raise exception 'BOOM!'; end$$ language plpgsql
create trigger convslot_test_parent_update after update on convslot_test_parent referencing old table as old_rows new table as new_rows for each statement execute procedure convslot_trig4()
insert into convslot_test_parent (id, val) values (1, 2)
savepoint svp
update convslot_test_parent set val = 3
rollback to savepoint svp
drop table convslot_test_parent
drop function convslot_trig4()
